// v2 parser — robust extraction with dual fallback, node-type capture, and message truncation.
// Replaces the v1 string-only `lastNodeExecuted` extraction.

const err = $input.first().json;
const execution = err.execution || {};
const trigger = err.execution?.error || err.error || {};

const workflowName = err.workflow?.name || 'Unknown workflow';
const workflowId = err.workflow?.id || '';

const lastNode = trigger.node?.name
             || err.execution?.lastNodeExecuted
             || 'unknown';
const lastNodeType = trigger.node?.type || 'unknown';

const rawMessage = trigger.message
              || trigger.description
              || 'No error message available';
const message = String(rawMessage).substring(0, 1000);

// Optional: capture a short snippet of the failing item's data, if present.
// Useful for diagnosing data-shape issues. Stays under JSONB sanity.
let payloadSnippet = null;
try {
  const itemContext = trigger.context?.itemIndex !== undefined
    ? trigger.context
    : null;
  if (itemContext) {
    const snippet = JSON.stringify(itemContext).substring(0, 500);
    payloadSnippet = JSON.parse(snippet.endsWith('}') ? snippet : snippet + '"}');
  }
} catch (e) {
  payloadSnippet = null;
}

return [{
  json: {
    workflow_name: workflowName,
    workflow_id: workflowId,
    execution_id: execution.id || '',
    execution_url: execution.url || '',
    failed_node_name: lastNode,
    failed_node_type: lastNodeType,
    error_message: message,
    payload_snippet: payloadSnippet,
    timestamp: new Date().toISOString()
  }
}];
